# test_group_by.py
import pytest

# Adjust the import path to where group_by lives
# from your_module import group_by

def group_by(items: list, key_fn) -> dict:
    result = {}
    for item in items:
        k = key_fn(item)
        result.setdefault(k, []).append(item)
    return result


def test_group_by_happy_path_integers_by_parity():
    items = [1, 2, 3, 4, 5, 6]
    res = group_by(items, lambda x: "even" if x % 2 == 0 else "odd")

    assert set(res.keys()) == {"even", "odd"}
    assert res["even"] == [2, 4, 6]
    assert res["odd"] == [1, 3, 5]


def test_group_by_happy_path_preserves_insertion_order_within_each_group():
    # Items should remain in the same relative order per key
    items = ["a1", "b1", "a2", "b2", "a3"]
    res = group_by(items, lambda s: s[0])

    assert res["a"] == ["a1", "a2", "a3"]
    assert res["b"] == ["b1", "b2"]


def test_group_by_edge_empty_input():
    assert group_by([], lambda x: x) == {}


def test_group_by_edge_single_item():
    res = group_by([42], lambda x: "answer" if x == 42 else "other")
    assert res == {"answer": [42]}


def test_group_by_edge_none_key_allowed():
    # key_fn can return None; it should be used as a dict key
    items = [1, 2, 3]
    res = group_by(items, lambda x: None if x < 3 else "big")

    assert set(res.keys()) == {None, "big"}
    assert res[None] == [1, 2]
    assert res["big"] == [3]


def test_group_by_edge_unhashable_key_raises_typeerror():
    # Dict keys must be hashable; returning an unhashable value should error
    items = [1, 2]
    with pytest.raises(TypeError):
        group_by(items, lambda x: [x])  # list is unhashable


def test_group_by_error_key_fn_raises_propagates_exception():
    def key_fn(_):
        raise ValueError("boom")

    with pytest.raises(ValueError, match="boom"):
        group_by([1, 2, 3], key_fn)


def test_group_by_error_items_not_iterable_raises_typeerror():
    # Since the function iterates over `items`, a non-iterable should fail
    with pytest.raises(TypeError):
        group_by(123, lambda x: x)


def test_group_by_error_key_fn_not_callable_raises_typeerror():
    with pytest.raises(TypeError):
        group_by([1, 2, 3], key_fn=None)
